form:Form.form:Scripts:
		function REPORTE() 
{   
	var aviso = Ctrl("MAIN_GRID").GetCellSelectedXValue("oi_aviso"); 
	var cv = Ctrl("oi_cv").GetXValue(); 

	var PARAM=new NomadXML("DATOS");

	PARAM.SetAttr("oi_aviso",aviso);
	PARAM.SetAttr("oi_cv",cv);		

	var nSQL = GetProxy().SQLService();
 	var resultado = nSQL.GetOBJ(Ctrl("main").getResource("QRY_RECLUT"), PARAM.ToString());

	if(resultado.flag!=0)
	{
		var PARAM2=new NomadXML("DATOS");
	 	PARAM2.SetAttr("oi_aviso",aviso);
		PARAM2.SetAttr("oi_reclutado",resultado.oi_reclutado);
		PARAM2.SetAttr("c_estado","");
		PARAM2.SetAttr("l_excluir","");	
		openNewFlow ("NucleusRH.Base.SeleccionDePostulantes.Reclutados.flow", "adm-reclutados", PARAM2.ToString(), null, "L");	
	}
	else
	{
		alert("No se encontraron registros para Reclutados - El CV sólo esta postulado al aviso");	
	}

}
